import{_ as a,o as t,c as i,ae as l}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"Ultimate HF Fleet Keep-Alive & Persistence Protocol","description":"How Hugging Face Spaces must stay awake, preserve state, and avoid accidental data loss.","frontmatter":{"title":"Ultimate HF Fleet Keep-Alive & Persistence Protocol","description":"How Hugging Face Spaces must stay awake, preserve state, and avoid accidental data loss."},"headers":[],"relativePath":"best-practices/hf-fleet-keepalive.md","filePath":"best-practices/hf-fleet-keepalive.md"}'),r={name:"best-practices/hf-fleet-keepalive.md"};function s(o,e,n,h,c,p){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="ultimate-hf-fleet-keep-alive-persistence-protocol" tabindex="-1">Ultimate HF Fleet Keep-Alive &amp; Persistence Protocol <a class="header-anchor" href="#ultimate-hf-fleet-keep-alive-persistence-protocol" aria-label="Permalink to &quot;Ultimate HF Fleet Keep-Alive &amp; Persistence Protocol&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> A Hugging Face Free VM is disposable by default. If you do not actively keep it warm and persist critical state, you are building on sand.</p></blockquote><hr><h2 id="_1-why-this-exists" tabindex="-1">1. Why This Exists <a class="header-anchor" href="#_1-why-this-exists" aria-label="Permalink to &quot;1. Why This Exists&quot;">​</a></h2><p>HF Spaces on free tiers can sleep. Sleep means:</p><ul><li>memory is gone</li><li>in-flight sessions die</li><li>temporary files vanish</li><li>browser/auth state may be lost</li></ul><p>Therefore every meaningful HF-hosted agent must have:</p><ol><li>a keep-alive strategy</li><li>a persistence strategy</li><li>a recovery strategy</li></ol><hr><h2 id="_2-keep-alive-strategy" tabindex="-1">2. Keep-Alive Strategy <a class="header-anchor" href="#_2-keep-alive-strategy" aria-label="Permalink to &quot;2. Keep-Alive Strategy&quot;">​</a></h2><h3 id="canonical-pattern" tabindex="-1">Canonical pattern <a class="header-anchor" href="#canonical-pattern" aria-label="Permalink to &quot;Canonical pattern&quot;">​</a></h3><p>Use a centralized scheduler (n8n on OCI VM) that pings every active HF Space health endpoint on a fixed interval.</p><h3 id="why-centralized" tabindex="-1">Why centralized <a class="header-anchor" href="#why-centralized" aria-label="Permalink to &quot;Why centralized&quot;">​</a></h3><p>A decentralized “each agent pings itself” model is fragile and harder to audit. The OCI scheduler is stable, visible, and cheap.</p><h3 id="recommended-interval" tabindex="-1">Recommended interval <a class="header-anchor" href="#recommended-interval" aria-label="Permalink to &quot;Recommended interval&quot;">​</a></h3><p>Every ~45 minutes for free-tier sleep prevention, unless platform behavior changes.</p><hr><h2 id="_3-persistence-strategy" tabindex="-1">3. Persistence Strategy <a class="header-anchor" href="#_3-persistence-strategy" aria-label="Permalink to &quot;3. Persistence Strategy&quot;">​</a></h2><p>Never rely on the HF VM filesystem for important long-lived state. Use one of:</p><ul><li>Hugging Face Dataset as persistence store</li><li>Supabase / remote DB for structured state</li><li>Git repository for durable text/config state</li></ul><h3 id="typical-persisted-items" tabindex="-1">Typical persisted items <a class="header-anchor" href="#typical-persisted-items" aria-label="Permalink to &quot;Typical persisted items&quot;">​</a></h3><ul><li>auth/session bundles</li><li>queue checkpoints</li><li>agent state snapshots</li><li>generated artifacts requiring recovery</li></ul><hr><h2 id="_4-recovery-strategy" tabindex="-1">4. Recovery Strategy <a class="header-anchor" href="#_4-recovery-strategy" aria-label="Permalink to &quot;4. Recovery Strategy&quot;">​</a></h2><p>On restart, the agent should:</p><ol><li>restore persisted state</li><li>verify auth/session validity</li><li>resume pending jobs safely</li><li>emit a recovery log/heartbeat</li></ol><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Without a recovery path, every HF restart becomes hidden data loss.</p><hr><h2 id="_5-what-must-never-be-local-only" tabindex="-1">5. What Must Never Be Local-Only <a class="header-anchor" href="#_5-what-must-never-be-local-only" aria-label="Permalink to &quot;5. What Must Never Be Local-Only&quot;">​</a></h2><p>Do <strong>not</strong> leave only on the HF filesystem:</p><ul><li>browser auth you cannot cheaply recreate</li><li>workflow queue state</li><li>issue mapping state</li><li>important logs or evidence</li><li>generated outputs the user depends on</li></ul><hr><h2 id="_6-health-endpoint-requirement" tabindex="-1">6. Health Endpoint Requirement <a class="header-anchor" href="#_6-health-endpoint-requirement" aria-label="Permalink to &quot;6. Health Endpoint Requirement&quot;">​</a></h2><p>Every HF-hosted service should expose a lightweight health endpoint such as:</p><ul><li><code>/health</code></li><li><code>/status</code></li><li>a tiny JSON heartbeat route</li></ul><p>This is what the keep-alive scheduler pings and what operators use for status checks.</p><hr><h2 id="_7-operational-checklist" tabindex="-1">7. Operational Checklist <a class="header-anchor" href="#_7-operational-checklist" aria-label="Permalink to &quot;7. Operational Checklist&quot;">​</a></h2><ul><li>[ ] health endpoint exists</li><li>[ ] n8n keep-alive poller includes the Space URL</li><li>[ ] important state is persisted remotely</li><li>[ ] restart flow restores state</li><li>[ ] recovery produces observable logs</li></ul><hr><h2 id="_8-final-rule" tabindex="-1">8. Final Rule <a class="header-anchor" href="#_8-final-rule" aria-label="Permalink to &quot;8. Final Rule&quot;">​</a></h2><p><strong>HF Spaces are excellent workers, but terrible memory.</strong> Treat them like resumable executors, not durable homes.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p>',45)])])}const m=a(r,[["render",s]]);export{u as __pageData,m as default};
